frameworks.custom_css:
.swot-grid { display: grid; grid-template-columns: 1fr 1fr; gap: 1.5rem; margin: 2rem 0; }
.swot-quadrant { padding: 1.5rem; border-radius: 8px; border: 2px solid; }
.strengths { border-color: #10b981; background: #10b98110; }
.weaknesses { border-color: #f59e0b; background: #f59e0b10; }
.opportunities { border-color: #3b82f6; background: #3b82f610; }
.threats { border-color: #ef4444; background: #ef444410; }

.forces-list { display: flex; flex-direction: column; gap: 1.5rem; }
.force-card { padding: 1.5rem; border-radius: 8px; border: 1px solid hsl(var(--border)); }
.force-header { display: flex; justify-content: between; align-items: center; margin-bottom: 1rem; }
.intensity-badge { padding: 0.25rem 0.75rem; border-radius: 4px; font-size: 0.875rem; font-weight: 600; }
.intensity-badge.High { background: #ef444420; color: #ef4444; }
.intensity-badge.Medium { background: #f59e0b20; color: #f59e0b; }
.intensity-badge.Low { background: #10b98120; color: #10b981; }

.bmc-grid { display: grid; grid-template-columns: repeat(5, 1fr); grid-template-rows: repeat(3, auto); gap: 1rem; margin: 2rem 0; }
.bmc-block { padding: 1rem; border: 2px solid hsl(var(--primary)); border-radius: 8px; background: hsl(var(--card)); }
.partnerships { grid-column: 1; grid-row: 1/3; }
.value { grid-column: 3; grid-row: 1/3; }
.segments { grid-column: 5; grid-row: 1/3; }
.costs { grid-column: 1/4; grid-row: 3; }
.revenue { grid-column: 4/6; grid-row: 3; }

.pestle-grid { display: grid; grid-template-columns: repeat(2, 1fr); gap: 1.5rem; margin: 2rem 0; }
.pestle-factor { padding: 1.5rem; border-radius: 8px; border: 1px solid hsl(var(--border)); background: hsl(var(--card)); }
.pestle-factor h3 { color: hsl(var(--primary)); margin-bottom: 1rem; }

.ansoff-grid { display: grid; grid-template-columns: 1fr 1fr; gap: 1.5rem; margin: 2rem 0; }
.ansoff-quadrant { padding: 1.5rem; border-radius: 8px; border: 2px solid hsl(var(--border)); }
.risk-badge { display: inline-block; padding: 0.25rem 0.75rem; border-radius: 4px; font-size: 0.75rem; font-weight: 600; margin-bottom: 1rem; }
.risk-badge.low { background: #10b98120; color: #10b981; }
.risk-badge.medium { background: #f59e0b20; color: #f59e0b; }
.risk-badge.high { background: #ef444420; color: #ef4444; }

.seven-s-diagram { display: grid; grid-template-columns: repeat(3, 1fr); gap: 1rem; margin: 2rem 0; }
.s-element { padding: 1.5rem; border-radius: 8px; border: 1px solid hsl(var(--border)); background: hsl(var(--card)); }
.shared-values { grid-column: 2; background: hsl(var(--primary) / 0.1); border: 2px solid hsl(var(--primary)); }
.alignment-section { margin-top: 2rem; padding: 1.5rem; border-radius: 8px; background: hsl(var(--muted)); }

.value-chain { display: flex; flex-direction: column; gap: 2rem; margin: 2rem 0; }
.support-activities, .primary-activities { display: grid; gap: 1rem; }
.support-activities { grid-template-columns: repeat(4, 1fr); }
.primary-activities { grid-template-columns: repeat(5, 1fr); }
.activity-card { padding: 1rem; border-radius: 8px; border: 1px solid hsl(var(--border)); background: hsl(var(--card)); }
.activity-card.primary { border: 2px solid hsl(var(--primary)); }

.bcg-matrix { display: grid; grid-template-columns: 1fr 1fr; gap: 1.5rem; margin: 2rem 0; }
.bcg-quadrant { padding: 1.5rem; border-radius: 8px; border: 2px solid; }
.bcg-quadrant .description { font-size: 0.875rem; color: hsl(var(--muted-foreground)); margin-bottom: 1rem; }
.stars { border-color: #fbbf24; background: #fbbf2410; }
.questions { border-color: #8b5cf6; background: #8b5cf610; }
.cows { border-color: #10b981; background: #10b98110; }
.dogs { border-color: #6b7280; background: #6b728010; }
.portfolio-recommendations { margin-top: 2rem; padding: 1.5rem; background: hsl(var(--muted)); border-radius: 8px; }

.bsc-grid { display: grid; grid-template-columns: 1fr 1fr; gap: 1.5rem; margin: 2rem 0; }
.bsc-perspective { padding: 1.5rem; border-radius: 8px; border: 2px solid; }
.financial { border-color: #10b981; background: #10b98110; }
.customer { border-color: #3b82f6; background: #3b82f610; }
.process { border-color: #8b5cf6; background: #8b5cf610; }
.learning { border-color: #f59e0b; background: #f59e0b10; }
.objective { margin: 1rem 0; padding: 1rem; background: hsl(var(--card)); border-radius: 4px; }

.four-actions { display: grid; grid-template-columns: 1fr 1fr; gap: 1.5rem; margin: 2rem 0; }
.action-quadrant { padding: 1.5rem; border-radius: 8px; border: 2px solid; }
.action-quadrant .subtitle { font-size: 0.875rem; color: hsl(var(--muted-foreground)); margin-bottom: 1rem; }
.eliminate { border-color: #ef4444; background: #ef444410; }
.reduce { border-color: #f59e0b; background: #f59e0b10; }
.raise { border-color: #10b981; background: #10b98110; }
.create { border-color: #3b82f6; background: #3b82f610; }
.value-innovation { margin-top: 2rem; padding: 1.5rem; background: hsl(var(--primary) / 0.1); border-radius: 8px; border: 2px solid hsl(var(--primary)); }
